// Parsed student data from Google Spreadsheet
// Fields: full_name, email, phone, weight, height, birth_date, physical_activity, objective, current_protocol, comorbidities

function parseHeight(val: string | undefined): number | null {
  if (!val || val.trim() === "") return null;
  const n = parseFloat(val.replace(",", "."));
  if (isNaN(n)) return null;
  // If value is less than 3, it's in meters, convert to cm
  return n < 3 ? Math.round(n * 100) : Math.round(n);
}

function parseWeight(val: string | undefined): number | null {
  if (!val || val.trim() === "") return null;
  const cleaned = val.replace(",", ".").replace(/[^\d.]/g, "");
  const n = parseFloat(cleaned);
  return isNaN(n) ? null : Math.round(n * 10) / 10;
}

function parseBirthDate(val: string | undefined): string | null {
  if (!val || val.trim() === "") return null;
  // Check if it's a date format like "4/28/1997" or "10/12/1989"
  const dateMatch = val.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})$/);
  if (dateMatch) {
    const [, month, day, year] = dateMatch;
    return `${year}-${month.padStart(2, "0")}-${day.padStart(2, "0")}`;
  }
  // It's likely an age number
  const age = parseInt(val);
  if (!isNaN(age) && age > 0 && age < 120) {
    const birthYear = new Date().getFullYear() - age;
    return `${birthYear}-01-01`;
  }
  return null;
}

function cleanPhone(val: string | undefined): string {
  if (!val || val.trim() === "") return "";
  const digits = val.replace(/\D/g, "");
  if (digits.length < 10) return "";
  if (digits.length === 11) return `(${digits.slice(0, 2)}) ${digits.slice(2, 7)}-${digits.slice(7)}`;
  if (digits.length === 10) return `(${digits.slice(0, 2)}) ${digits.slice(2, 6)}-${digits.slice(6)}`;
  return digits;
}

