export function getSpreadsheetStudents(): ParsedStudent[] {
  return rawData.map((r) => ({
    full_name: r.full_name,
    email: r.email,
    phone: cleanPhone(r.telefone),
    weight: parseWeight(r.peso),
    height: parseHeight(r.altura),
    birth_date: parseBirthDate(r.nascimento),
    physical_activity: r.atividade || "...",
    objective: r.objetivo || "...",
    current_protocol: r.medicamentos || "...",
    comorbidities: r.comorbidades || "...",
  }));
}
